/**
 * StrategyDetailPage — Full detail view for a single strategy card.
 *
 * Displays:
 * - Title, subtitle, priority, status
 * - Full evidence list
 * - Content direction suggestion
 * - A/B test variables table
 * - Expected KPIs
 * - Budget suggestion
 * - Audience targeting
 * - Linked insights + linked content
 * - Review action bar (reuses ReviewActionBar)
 */
import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Chip,
  Button,
  Divider,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  CircularProgress,
  Alert,
  Stack,
  Breadcrumbs,
  Link,
  List,
  ListItem,
  ListItemText,
} from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import { getStrategyCard, updateStrategyCardReview } from '@/shared/db/strategy.db';
import { getInsight } from '@/shared/db/insight.db';
import ReviewActionBar from '@/features/insights/ReviewActionBar';
import type { StrategyCard as StrategyCardType } from '@/shared/types/strategy';
import type { Insight } from '@/shared/types/insight';
import type { ReviewLog } from '@/shared/types/insight';

/** Priority color */
function getPriorityColor(priority: string) {
  switch (priority) {
    case 'P0':
      return { bg: '#FEE2E2', color: '#DC2626' };
    case 'P1':
      return { bg: '#FEF3C7', color: '#D97706' };
    case 'P2':
      return { bg: '#DBEAFE', color: '#2563EB' };
    default:
      return { bg: '#F3F4F6', color: '#6B7280' };
  }
}

function statusLabel(s: string): string {
  const map: Record<string, string> = { active: '执行中', draft: '草稿', archived: '已归档' };
  return map[s] ?? s;
}

function reviewLabel(s: string): string {
  const map: Record<string, string> = { confirmed: '已确认', pending: '待审核', rejected: '已驳回' };
  return map[s] ?? s;
}

const StrategyDetailPage: React.FC = () => {
  const { platform, id } = useParams<{ platform: string; id: string }>();
  const navigate = useNavigate();

  const [strategy, setStrategy] = useState<StrategyCardType | null>(null);
  const [linkedInsights, setLinkedInsights] = useState<Insight[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!id) return;
    (async () => {
      setLoading(true);
      setError(null);
      try {
        const card = await getStrategyCard(id);
        if (!card) {
          setError('策略卡未找到');
          setLoading(false);
          return;
        }
        setStrategy(card);

        // Load linked insights
        if (card.linkedInsightIds && card.linkedInsightIds.length > 0) {
          const insights: Insight[] = [];
          for (const insId of card.linkedInsightIds) {
            const ins = await getInsight(insId);
            if (ins) insights.push(ins);
          }
          setLinkedInsights(insights);
        }
      } catch (err) {
        console.error('Failed to load strategy card:', err);
        setError('加载策略卡失败');
      } finally {
        setLoading(false);
      }
    })();
  }, [id]);

  const handleConfirm = async (strategyId: string) => {
    if (!strategy) return;
    const logEntry: ReviewLog = {
      action: 'confirmed',
      timestamp: new Date().toISOString(),
      operator: '老薛',
      changes: null,
    };
    const reviewLog = [...strategy.reviewLog, logEntry];
    await updateStrategyCardReview(strategyId, 'confirmed', reviewLog);
    setStrategy({ ...strategy, reviewStatus: 'confirmed', reviewLog });
  };

  const handleReject = async (strategyId: string, reason: string) => {
    if (!strategy) return;
    const logEntry: ReviewLog = {
      action: 'rejected',
      timestamp: new Date().toISOString(),
      operator: '老薛',
      changes: reason,
    };
    const reviewLog = [...strategy.reviewLog, logEntry];
    await updateStrategyCardReview(strategyId, 'rejected', reviewLog);
    setStrategy({ ...strategy, reviewStatus: 'rejected', reviewLog });
  };

  const handleEdit = async (strategyId: string, newContent: string) => {
    if (!strategy) return;
    const logEntry: ReviewLog = {
      action: 'edited',
      timestamp: new Date().toISOString(),
      operator: '老薛',
      changes: '人工编辑策略内容',
    };
    const reviewLog = [...strategy.reviewLog, logEntry];
    await updateStrategyCardReview(strategyId, 'confirmed', reviewLog);
    setStrategy({
      ...strategy,
      reviewStatus: 'confirmed',
      reviewLog,
      contentDirection: newContent,
    });
  };

  if (loading) {
    return (
      <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%' }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error || !strategy) {
    return (
      <Box sx={{ p: 4 }}>
        <Alert severity="error" action={
          <Button size="small" onClick={() => navigate(-1)}>返回</Button>
        }>
          {error ?? '策略卡未找到'}
        </Alert>
      </Box>
    );
  }

  const pColor = getPriorityColor(strategy.priority);
  const platformLabel = strategy.platform === 'xhs' ? '小红书' : '抖音';

  return (
    <Box sx={{ p: 3, maxWidth: 960, mx: 'auto' }}>
      {/* Breadcrumbs */}
      <Breadcrumbs sx={{ mb: 2 }}>
        <Link
          underline="hover"
          color="inherit"
          sx={{ cursor: 'pointer' }}
          onClick={() => navigate(`/strategy/${platform}`)}
        >
          策略卡
        </Link>
        <Typography color="text.primary">{strategy.title}</Typography>
      </Breadcrumbs>

      <Button
        startIcon={<ArrowBackIcon />}
        size="small"
        sx={{ mb: 2 }}
        onClick={() => navigate(-1)}
      >
        返回列表
      </Button>

      {/* Header Card */}
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Stack direction="row" spacing={1} alignItems="center" sx={{ mb: 2 }} flexWrap="wrap">
            <Chip
              label={strategy.priority}
              size="small"
              sx={{ bgcolor: pColor.bg, color: pColor.color, fontWeight: 700 }}
            />
            <Chip
              label={statusLabel(strategy.status)}
              size="small"
              color={strategy.status === 'active' ? 'success' : 'default'}
              variant="outlined"
            />
            <Chip
              label={reviewLabel(strategy.reviewStatus)}
              size="small"
              color={
                strategy.reviewStatus === 'confirmed'
                  ? 'success'
                  : strategy.reviewStatus === 'rejected'
                    ? 'error'
                    : 'warning'
              }
            />
            <Chip label={`📕 ${platformLabel}`} size="small" variant="outlined" />
          </Stack>

          <Typography variant="h5" fontWeight={700} gutterBottom>
            {strategy.title}
          </Typography>
          {strategy.subtitle && (
            <Typography variant="body1" color="text.secondary" gutterBottom>
              {strategy.subtitle}
            </Typography>
          )}
        </CardContent>
      </Card>

      {/* Review action bar (for pending) */}
      {strategy.reviewStatus === 'pending' && (
        <Box sx={{ mb: 3 }}>
          <ReviewActionBar
            insightId={strategy.id}
            onConfirm={handleConfirm}
            onReject={handleReject}
            onEdit={handleEdit}
          />
        </Box>
      )}

      {/* Content Direction */}
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Typography variant="h6" fontWeight={600} gutterBottom>
            📝 内容方向建议
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ whiteSpace: 'pre-wrap' }}>
            {strategy.contentDirection}
          </Typography>
        </CardContent>
      </Card>

      {/* Evidence */}
      {strategy.evidence && strategy.evidence.length > 0 && (
        <Card sx={{ mb: 3 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              💬 评论证据 ({strategy.evidence.length}条)
            </Typography>
            <List dense>
              {strategy.evidence.map((ev, idx) => (
                <ListItem key={idx} sx={{ pl: 2, borderLeft: '2px solid', borderColor: 'divider', mb: 1 }}>
                  <ListItemText
                    primary={ev}
                    primaryTypographyProps={{
                      variant: 'body2',
                      fontStyle: 'italic',
                      color: 'text.secondary',
                    }}
                  />
                </ListItem>
              ))}
            </List>
          </CardContent>
        </Card>
      )}

      {/* A/B Test Variables */}
      {strategy.abTestVariables && strategy.abTestVariables.length > 0 && (
        <Card sx={{ mb: 3 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              🧪 A/B 测试变量
            </Typography>
            <TableContainer component={Paper} variant="outlined">
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell sx={{ fontWeight: 600 }}>测试组</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>方向</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>变量</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>KPI</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {strategy.abTestVariables.map((v, idx) => (
                    <TableRow key={idx}>
                      <TableCell>{v.group} 组</TableCell>
                      <TableCell>{v.direction}</TableCell>
                      <TableCell>{v.variable}</TableCell>
                      <TableCell>{v.kpi}</TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </CardContent>
        </Card>
      )}

      {/* KPIs + Budget + Audience row */}
      <Box sx={{ display: 'flex', gap: 2, mb: 3, flexDirection: { xs: 'column', md: 'row' } }}>
        {/* Expected KPIs */}
        <Card sx={{ flex: 1 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              📊 预期 KPI
            </Typography>
            <Stack direction="row" spacing={1} flexWrap="wrap" useFlexGap>
              {strategy.expectedKPIs.map((kpi, idx) => (
                <Chip key={idx} label={kpi} color="primary" variant="outlined" size="small" />
              ))}
            </Stack>
          </CardContent>
        </Card>

        {/* Budget */}
        <Card sx={{ flex: 1 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              💰 预算建议
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {strategy.budgetSuggestion}
            </Typography>
          </CardContent>
        </Card>

        {/* Audience */}
        <Card sx={{ flex: 1 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              🎯 人群定向
            </Typography>
            <Stack direction="row" spacing={0.5} flexWrap="wrap" useFlexGap>
              {(strategy.audienceTarget || []).map((a, idx) => (
                <Chip key={idx} label={a} size="small" variant="outlined" />
              ))}
            </Stack>
          </CardContent>
        </Card>
      </Box>

      {/* Linked Insights */}
      {linkedInsights.length > 0 && (
        <Card sx={{ mb: 3 }}>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              🔗 关联洞察 ({linkedInsights.length})
            </Typography>
            <List dense>
              {linkedInsights.map((ins) => (
                <ListItem key={ins.id}>
                  <ListItemText
                    primary={ins.title}
                    secondary={ins.content.substring(0, 120) + '...'}
                    primaryTypographyProps={{ variant: 'body2', fontWeight: 500 }}
                    secondaryTypographyProps={{ variant: 'caption' }}
                  />
                </ListItem>
              ))}
            </List>
          </CardContent>
        </Card>
      )}

      {/* Review log */}
      {strategy.reviewLog && strategy.reviewLog.length > 0 && (
        <Card>
          <CardContent>
            <Typography variant="h6" fontWeight={600} gutterBottom>
              📋 审核记录
            </Typography>
            <List dense>
              {strategy.reviewLog.map((log, idx) => (
                <ListItem key={idx}>
                  <ListItemText
                    primary={`${log.operator} · ${log.action}`}
                    secondary={`${log.timestamp}${log.changes ? ` — ${log.changes}` : ''}`}
                    primaryTypographyProps={{ variant: 'caption', fontWeight: 500 }}
                    secondaryTypographyProps={{ variant: 'caption', color: 'text.secondary' }}
                  />
                </ListItem>
              ))}
            </List>
          </CardContent>
        </Card>
      )}
    </Box>
  );
};

export default StrategyDetailPage;
